#include <oesdk/process.h>
#include <string.h>
static OesdkProcess OesdkProcesses[OESDK_PROCESS_MAX_COUNT]; static OesdkProcessId OesdkNextProcessId=UINT64_C(1);
OesdkStatus OesdkProcessGet(OesdkProcessId Id,OesdkProcess **Out){size_t I;if(Out==NULL)return OESDK_STATUS_INVALID_ARGUMENT;for(I=0;I<OESDK_PROCESS_MAX_COUNT;++I)if(OesdkProcesses[I].Id==Id){*Out=&OesdkProcesses[I];return OESDK_STATUS_SUCCESS;}return OESDK_STATUS_NOT_FOUND;}
OesdkStatus OesdkProcessCreate(const char*Name,uint64_t Root,OesdkProcessId*Id){size_t I,L;OesdkStatus S;if(Name==NULL||Id==NULL)return OESDK_STATUS_INVALID_ARGUMENT;for(I=0;I<OESDK_PROCESS_MAX_COUNT&&OesdkProcesses[I].Id!=0U;++I){}if(I==OESDK_PROCESS_MAX_COUNT)return OESDK_STATUS_OUT_OF_MEMORY;memset(&OesdkProcesses[I],0,sizeof(OesdkProcesses[I]));S=OesdkAddressSpaceCreate(Root,&OesdkProcesses[I].AddressSpace);if(OESDK_FAILED(S))return S;OesdkProcesses[I].Id=OesdkNextProcessId++;OesdkProcesses[I].State=OesdkProcessStateCreated;for(L=0;Name[L]&&L<OESDK_PROCESS_NAME_MAX;++L)OesdkProcesses[I].Name[L]=Name[L];*Id=OesdkProcesses[I].Id;return OESDK_STATUS_SUCCESS;}
OesdkStatus OesdkProcessConfigureUserStack(OesdkProcessId Id,uintptr_t V,uintptr_t P,size_t Bytes){OesdkProcess*Proc;OesdkStatus S=OesdkProcessGet(Id,&Proc);size_t Pages;if(OESDK_FAILED(S)||Bytes==0U)return OESDK_FAILED(S)?S:OESDK_STATUS_INVALID_ARGUMENT;Pages=(Bytes+OESDK_VIRTUAL_PAGE_SIZE-1U)/OESDK_VIRTUAL_PAGE_SIZE;S=OesdkAddressSpaceMap(&Proc->AddressSpace,V,P,Pages,OESDK_VIRTUAL_FLAG_WRITABLE|OESDK_VIRTUAL_FLAG_NO_EXECUTE);if(OESDK_SUCCEEDED(S)){Proc->UserStackBase=V;Proc->UserStackBytes=Pages*OESDK_VIRTUAL_PAGE_SIZE;}return S;}
OesdkStatus OesdkProcessTerminate(OesdkProcessId Id,int32_t ExitCode){OesdkProcess*P;OesdkStatus S=OesdkProcessGet(Id,&P);if(OESDK_FAILED(S))return S;P->State=OesdkProcessStateTerminated;P->ExitCode=ExitCode;if(P->MainThreadId!=OESDK_THREAD_ID_INVALID)(void)OesdkThreadTerminate(P->MainThreadId);return OESDK_STATUS_SUCCESS;}
